from flask import Flask, request, jsonify
from flask_jwt_extended import jwt_required, get_jwt_identity
from werkzeug.security import generate_password_hash, check_password_hash

app = Flask(__name__)

# Assuming you have a User model defined elsewhere in your codebase
from models import User

@app.route('/api/users/<int:user_id>', methods=['PUT'])
@jwt_required()
def update_user(user_id):
    current_user = get_jwt_identity()

    # Load the user by both its identifier and the authenticated user or tenant scope
    user = User.query.get(user_id)
    
    if not user:
        return jsonify({'error': 'User not found'}), 404

    # Check object-level authorization before returning, updating, or deleting the resource
    if current_user != user.id and current_user != 1:  # Assuming admin role is 1
        return jsonify({'error': 'Forbidden'}), 403

    # Allowlist which fields can be updated instead of blindly applying all user input
    allowed_fields = ['email', 'username', 'role', 'account_status', 'subscription_tier']
    data = request.json

    for field in data:
        if field not in allowed_fields:
            return jsonify({'error': f'Invalid field: {field}'}), 400

    # Enforce role checks for admin-only functionality on the server side
    if current_user != 1 and 'role' in data and data['role'] == 'admin':
        return jsonify({'error': 'Forbidden'}), 403

    # Update user fields
    for field, value in data.items():
        setattr(user, field, value)

    user.save()

    return jsonify({'message': 'User updated successfully'}), 200